import React, { useState, useEffect } from "react";
import Page from "@/components/Page";
import { useAuth } from "@/context/AuthContext";
import { getCurrentUserService, updateUserProfileService } from "@/api/services/user/userService";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
  User,
  Mail,
  Shield,
  Building,
  Phone,
  Calendar,
  Settings as SettingsIcon,
  Save,
  Edit3,
  Camera,
  Crown,
  Globe,
  Clock,
  UserCheck,
  Sparkles,
  Zap
} from "lucide-react";
import { toast } from "sonner";

interface UserProfile {
  id: number;
  email: string;
  name?: string;
  first_name?: string;
  last_name?: string;
  username?: string;
  role?: string;
  org_id?: string;
  phone_number?: string;
  created_at?: string;
  last_login?: string;
}

const Settings: React.FC = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState({
    first_name: '',
    last_name: '',
    username: '',
    email: '',
    phone_number: ''
  });

  useEffect(() => {
    fetchUserProfile();
  }, [user]);

  const fetchUserProfile = async () => {
    try {
      setLoading(true);
      // Use user data from context first, then try API
      if (user) {
        const profileData = {
          ...user,
          phone_number: (user as any).phone_number || '',
          created_at: (user as any).created_at || '',
          last_login: (user as any).last_login || ''
        } as UserProfile;

        setProfile(profileData);
        setFormData({
          first_name: user.first_name || (user.name ? user.name.split(' ')[0] : ''),
          last_name: user.last_name || (user.name ? user.name.split(' ').slice(1).join(' ') : ''),
          username: user.username || '',
          email: user.email || '',
          phone_number: (user as any).phone_number || ''
        });
      } else {
        // Fallback to API call
        const userData = await getCurrentUserService();
        if (userData) {
          setProfile(userData as UserProfile);
          setFormData({
            first_name: userData.first_name || '',
            last_name: userData.last_name || '',
            username: userData.username || '',
            email: userData.email || '',
            phone_number: (userData as any).phone_number || ''
          });
        }
      }
    } catch (error) {
      console.error("Error fetching user profile:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field: string, value: string) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleSave = async () => {
    if (!profile) return;

    try {
      setSaving(true);
      const updatedUser = await updateUserProfileService({
        id: profile.id,
        ...formData
      });

      if (updatedUser) {
        setProfile(updatedUser as UserProfile);
        setIsEditing(false);
        toast.success("Profile updated successfully!");
      }
    } catch (error) {
      console.error("Error updating profile:", error);
      toast.error("Failed to update profile");
    } finally {
      setSaving(false);
    }
  };

  const getUserInitials = () => {
    if (profile?.first_name && profile?.last_name) {
      return `${profile.first_name.charAt(0)}${profile.last_name.charAt(0)}`.toUpperCase();
    } else if (profile?.name) {
      const names = profile.name.split(' ');
      if (names.length >= 2) {
        return `${names[0].charAt(0)}${names[1].charAt(0)}`.toUpperCase();
      }
      return profile.name.charAt(0).toUpperCase();
    } else if (profile?.username) {
      return profile.username.charAt(0).toUpperCase();
    } else if (profile?.email) {
      return profile.email.charAt(0).toUpperCase();
    }
    return 'U';
  };

  const getDisplayName = () => {
    if (profile?.first_name && profile?.last_name) {
      return `${profile.first_name} ${profile.last_name}`;
    } else if (profile?.name) {
      return profile.name;
    } else if (profile?.username) {
      return profile.username;
    }
    return 'User';
  };

  if (loading) {
    return (
      <Page>
        <div className="flex items-center justify-center min-h-[400px]">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
        </div>
      </Page>
    );
  }

  return (
    <Page>
      <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50 dark:from-slate-900 dark:via-slate-800 dark:to-slate-900">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {/* Modern Header */}
          <div className="mb-12">
            <div className="flex items-center space-x-4 mb-4">
              <div className="relative">
                <div className="absolute inset-0 bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl blur-lg opacity-20"></div>
                <div className="relative p-4 bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-white/20">
                  <SettingsIcon className="h-8 w-8 text-blue-600" />
                </div>
              </div>
              <div>
                <h1 className="text-4xl font-bold bg-gradient-to-r from-slate-900 to-slate-600 dark:from-white dark:to-slate-300 bg-clip-text text-transparent">
                  Account Settings
                </h1>
                <p className="text-lg text-slate-600 dark:text-slate-400 mt-1">
                  Manage your profile and account preferences
                </p>
              </div>
            </div>
            <div className="h-1 bg-gradient-to-r from-blue-600 via-purple-600 to-indigo-600 rounded-full w-24"></div>
          </div>

          {/* Hero Profile Section */}
          <div className="relative mb-12">
            <div className="absolute inset-0 bg-gradient-to-r from-blue-600/10 via-purple-600/10 to-indigo-600/10 rounded-3xl blur-3xl"></div>
            <Card className="relative border-0 shadow-2xl bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl">
              <CardContent className="p-8">
                <div className="flex flex-col lg:flex-row items-start lg:items-center justify-between space-y-6 lg:space-y-0">
                  <div className="flex items-center space-x-6">
                    <div className="relative group">
                      <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-purple-600 rounded-full blur opacity-25 group-hover:opacity-75 transition duration-1000 group-hover:duration-200"></div>
                      <Avatar className="relative h-24 w-24 border-4 border-white dark:border-slate-700 shadow-xl">
                        <AvatarImage src="" alt={getDisplayName()} />
                        <AvatarFallback className="bg-gradient-to-br from-blue-600 to-purple-600 text-white text-2xl font-bold">
                          {getUserInitials()}
                        </AvatarFallback>
                      </Avatar>
                      <Button
                        size="sm"
                        className="absolute -bottom-1 -right-1 h-10 w-10 rounded-full p-0 shadow-lg bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 border-2 border-white dark:border-slate-700"
                      >
                        <Camera className="h-4 w-4" />
                      </Button>
                    </div>
                    <div className="space-y-2">
                      <div className="flex items-center space-x-3">
                        <h2 className="text-3xl font-bold bg-gradient-to-r from-slate-900 to-slate-600 dark:from-white dark:to-slate-300 bg-clip-text text-transparent">
                          {getDisplayName()}
                        </h2>
                        <Badge className="bg-gradient-to-r from-emerald-500 to-teal-500 text-white border-0 px-3 py-1">
                          <Crown className="h-3 w-3 mr-1" />
                          {profile?.role || 'User'}
                        </Badge>
                      </div>
                      <div className="flex items-center space-x-4 text-slate-600 dark:text-slate-400">
                        <div className="flex items-center space-x-2">
                          <Mail className="h-4 w-4" />
                          <span className="font-medium">{profile?.email}</span>
                        </div>
                        {profile?.org_id && (
                          <div className="flex items-center space-x-2">
                            <Building className="h-4 w-4" />
                            <span className="font-medium">{profile.org_id}</span>
                          </div>
                        )}
                      </div>
                      <div className="flex items-center space-x-4">
                        <Badge variant="outline" className="flex items-center space-x-1 border-blue-200 text-blue-700 dark:border-blue-800 dark:text-blue-300">
                          <UserCheck className="h-3 w-3" />
                          <span>Verified Account</span>
                        </Badge>
                        <Badge variant="outline" className="flex items-center space-x-1 border-purple-200 text-purple-700 dark:border-purple-800 dark:text-purple-300">
                          <Sparkles className="h-3 w-3" />
                          <span>Premium</span>
                        </Badge>
                      </div>
                    </div>
                  </div>
                  <Button
                    onClick={() => setIsEditing(!isEditing)}
                    size="lg"
                    className={`px-8 py-3 rounded-xl font-semibold transition-all duration-200 ${
                      isEditing
                        ? "bg-slate-100 hover:bg-slate-200 text-slate-700 dark:bg-slate-700 dark:hover:bg-slate-600 dark:text-slate-300"
                        : "bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white shadow-lg hover:shadow-xl"
                    }`}
                  >
                    <Edit3 className="h-5 w-5 mr-2" />
                    {isEditing ? 'Cancel Edit' : 'Edit Profile'}
                  </Button>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Profile Information Section */}
          <div className="grid grid-cols-1 xl:grid-cols-3 gap-8 mb-12">
            <div className="xl:col-span-2">
              <Card className="border-0 shadow-xl bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl">
                <CardHeader className="pb-6">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-gradient-to-r from-blue-600 to-purple-600 rounded-lg">
                      <User className="h-5 w-5 text-white" />
                    </div>
                    <div>
                      <CardTitle className="text-xl font-bold text-slate-900 dark:text-white">
                        Profile Information
                      </CardTitle>
                      <CardDescription className="text-slate-600 dark:text-slate-400">
                        Update your personal information and contact details
                      </CardDescription>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="space-y-8">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-3">
                      <Label htmlFor="first_name" className="text-sm font-semibold text-slate-700 dark:text-slate-300">
                        First Name
                      </Label>
                      <Input
                        id="first_name"
                        value={formData.first_name}
                        onChange={(e) => handleInputChange('first_name', e.target.value)}
                        disabled={!isEditing}
                        className={`h-12 rounded-xl border-2 transition-all duration-200 ${
                          !isEditing
                            ? "bg-slate-50 dark:bg-slate-700/50 border-slate-200 dark:border-slate-600"
                            : "border-blue-200 dark:border-blue-800 focus:border-blue-500 dark:focus:border-blue-400"
                        }`}
                        placeholder="Enter your first name"
                      />
                    </div>
                    <div className="space-y-3">
                      <Label htmlFor="last_name" className="text-sm font-semibold text-slate-700 dark:text-slate-300">
                        Last Name
                      </Label>
                      <Input
                        id="last_name"
                        value={formData.last_name}
                        onChange={(e) => handleInputChange('last_name', e.target.value)}
                        disabled={!isEditing}
                        className={`h-12 rounded-xl border-2 transition-all duration-200 ${
                          !isEditing
                            ? "bg-slate-50 dark:bg-slate-700/50 border-slate-200 dark:border-slate-600"
                            : "border-blue-200 dark:border-blue-800 focus:border-blue-500 dark:focus:border-blue-400"
                        }`}
                        placeholder="Enter your last name"
                      />
                    </div>
                    <div className="space-y-3">
                      <Label htmlFor="username" className="text-sm font-semibold text-slate-700 dark:text-slate-300">
                        Username
                      </Label>
                      <Input
                        id="username"
                        value={formData.username}
                        onChange={(e) => handleInputChange('username', e.target.value)}
                        disabled={!isEditing}
                        className={`h-12 rounded-xl border-2 transition-all duration-200 ${
                          !isEditing
                            ? "bg-slate-50 dark:bg-slate-700/50 border-slate-200 dark:border-slate-600"
                            : "border-blue-200 dark:border-blue-800 focus:border-blue-500 dark:focus:border-blue-400"
                        }`}
                        placeholder="Enter your username"
                      />
                    </div>
                    <div className="space-y-3">
                      <Label htmlFor="email" className="text-sm font-semibold text-slate-700 dark:text-slate-300">
                        Email Address
                      </Label>
                      <Input
                        id="email"
                        type="email"
                        value={formData.email}
                        onChange={(e) => handleInputChange('email', e.target.value)}
                        disabled={!isEditing}
                        className={`h-12 rounded-xl border-2 transition-all duration-200 ${
                          !isEditing
                            ? "bg-slate-50 dark:bg-slate-700/50 border-slate-200 dark:border-slate-600"
                            : "border-blue-200 dark:border-blue-800 focus:border-blue-500 dark:focus:border-blue-400"
                        }`}
                        placeholder="Enter your email address"
                      />
                    </div>
                    <div className="space-y-3 md:col-span-2">
                      <Label htmlFor="phone_number" className="text-sm font-semibold text-slate-700 dark:text-slate-300">
                        Phone Number
                      </Label>
                      <Input
                        id="phone_number"
                        value={formData.phone_number}
                        onChange={(e) => handleInputChange('phone_number', e.target.value)}
                        disabled={!isEditing}
                        className={`h-12 rounded-xl border-2 transition-all duration-200 ${
                          !isEditing
                            ? "bg-slate-50 dark:bg-slate-700/50 border-slate-200 dark:border-slate-600"
                            : "border-blue-200 dark:border-blue-800 focus:border-blue-500 dark:focus:border-blue-400"
                        }`}
                        placeholder="Enter your phone number"
                      />
                    </div>
                  </div>

                  {isEditing && (
                    <div className="flex justify-end space-x-4 pt-6 border-t border-slate-200 dark:border-slate-700">
                      <Button
                        variant="outline"
                        size="lg"
                        className="px-8 py-3 rounded-xl font-semibold border-2 hover:bg-slate-50 dark:hover:bg-slate-700"
                        onClick={() => {
                          setIsEditing(false);
                          setFormData({
                            first_name: profile?.first_name || (profile?.name ? profile.name.split(' ')[0] : ''),
                            last_name: profile?.last_name || (profile?.name ? profile.name.split(' ').slice(1).join(' ') : ''),
                            username: profile?.username || '',
                            email: profile?.email || '',
                            phone_number: (profile as any)?.phone_number || ''
                          });
                        }}
                      >
                        Cancel
                      </Button>
                      <Button
                        onClick={handleSave}
                        disabled={saving}
                        size="lg"
                        className="px-8 py-3 rounded-xl font-semibold bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white shadow-lg hover:shadow-xl transition-all duration-200"
                      >
                        <Save className="h-5 w-5 mr-2" />
                        {saving ? 'Saving...' : 'Save Changes'}
                      </Button>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>

            {/* Account Stats Sidebar */}
            <div className="space-y-6">
              <Card className="border-0 shadow-xl bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl">
                <CardHeader className="pb-4">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-gradient-to-r from-emerald-500 to-teal-500 rounded-lg">
                      <Shield className="h-5 w-5 text-white" />
                    </div>
                    <CardTitle className="text-lg font-bold text-slate-900 dark:text-white">
                      Account Details
                    </CardTitle>
                  </div>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="p-4 bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20 rounded-xl border border-blue-100 dark:border-blue-800">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-3">
                        <User className="h-5 w-5 text-blue-600" />
                        <span className="font-semibold text-slate-700 dark:text-slate-300">User ID</span>
                      </div>
                      <Badge className="bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200 border-0">
                        #{profile?.id}
                      </Badge>
                    </div>
                  </div>

                  <div className="p-4 bg-gradient-to-r from-purple-50 to-pink-50 dark:from-purple-900/20 dark:to-pink-900/20 rounded-xl border border-purple-100 dark:border-purple-800">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-3">
                        <Crown className="h-5 w-5 text-purple-600" />
                        <span className="font-semibold text-slate-700 dark:text-slate-300">Role</span>
                      </div>
                      <Badge className="bg-gradient-to-r from-purple-500 to-pink-500 text-white border-0">
                        {profile?.role || 'User'}
                      </Badge>
                    </div>
                  </div>

                  {profile?.org_id && (
                    <div className="p-4 bg-gradient-to-r from-emerald-50 to-teal-50 dark:from-emerald-900/20 dark:to-teal-900/20 rounded-xl border border-emerald-100 dark:border-emerald-800">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center space-x-3">
                          <Building className="h-5 w-5 text-emerald-600" />
                          <span className="font-semibold text-slate-700 dark:text-slate-300">Organization</span>
                        </div>
                        <Badge className="bg-emerald-100 text-emerald-800 dark:bg-emerald-900 dark:text-emerald-200 border-0">
                          {profile.org_id}
                        </Badge>
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>

              <Card className="border-0 shadow-xl bg-white/80 dark:bg-slate-800/80 backdrop-blur-xl">
                <CardHeader className="pb-4">
                  <div className="flex items-center space-x-3">
                    <div className="p-2 bg-gradient-to-r from-orange-500 to-red-500 rounded-lg">
                      <Clock className="h-5 w-5 text-white" />
                    </div>
                    <CardTitle className="text-lg font-bold text-slate-900 dark:text-white">
                      Activity
                    </CardTitle>
                  </div>
                </CardHeader>
                <CardContent className="space-y-4">
                  {(profile as any)?.created_at && (
                    <div className="p-4 bg-gradient-to-r from-amber-50 to-orange-50 dark:from-amber-900/20 dark:to-orange-900/20 rounded-xl border border-amber-100 dark:border-amber-800">
                      <div className="flex items-center space-x-3 mb-2">
                        <Calendar className="h-5 w-5 text-amber-600" />
                        <span className="font-semibold text-slate-700 dark:text-slate-300">Member Since</span>
                      </div>
                      <p className="text-sm text-slate-600 dark:text-slate-400 ml-8">
                        {new Date((profile as any).created_at).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric'
                        })}
                      </p>
                    </div>
                  )}

                  {(profile as any)?.last_login && (
                    <div className="p-4 bg-gradient-to-r from-green-50 to-emerald-50 dark:from-green-900/20 dark:to-emerald-900/20 rounded-xl border border-green-100 dark:border-green-800">
                      <div className="flex items-center space-x-3 mb-2">
                        <Zap className="h-5 w-5 text-green-600" />
                        <span className="font-semibold text-slate-700 dark:text-slate-300">Last Active</span>
                      </div>
                      <p className="text-sm text-slate-600 dark:text-slate-400 ml-8">
                        {new Date((profile as any).last_login).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric',
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </p>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </div>
        </div>
      </div>
    </Page>
  );
};

export default Settings;
